static Value *foldAndOrOfICmpEqAndMaskedICmp(ICmpInst *LHS, ICmpInst *RHS,
                                             bool IsAnd, IRBuilderBase &Builder) {
  // (icmp eq X, C1) | (icmp eq (X & ~C1), C2) -> icmp ult (X - C1), (C2 - C1 + 1)
  // Example: X == 127 | (X & -32) == 128 -> (X - 127) < 33
  // But wait, the mask in the task is -32, which is ~31, not ~127.
  // The expected result is: (X - 127) u< 33
  // Let's analyze: 127 + 33 = 160. So X is in [127, 159].
  // 127 is 01111111
  // (X & -32) == 128 means X is in [128, 159]
  // 127 is exactly 128 - 1, and fits right below the range.
  // So X == 127 | X in [128, 159] -> X in [127, 159]
  // The mask is -32 (which is ~31), so X & -32 == 128 means X's lower 5 bits can be anything from 0 to 31.
  // So X is in [128, 128 + 31] = [128, 159].
  // This is a range check!
  // foldAndOrOfICmpsUsingRanges should have caught this. Why didn't it?
}
